    ts = datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%S")

    readiness_checks = []
    for i, check_name in enumerate(_MRER_MANDATORY_CHECKS, start=1):
        rid = f"mrer-{ts}-{i:02d}"
